-- ملء محتوى عنقود "تاريخ التشريع الإسلامي" (tarikh-tashri) — أربعة
-- تصنيفات فرعية، كلها draft (استنفاد كامل للعنقود): التشريع في عصر
-- النبوة والصحابة والتابعين، المدارس الفقهية وتدوين الفقه، تاريخ المذاهب
-- الأربعة والاجتهاد والقضاء، المجامع الفقهية والتقنين المعاصر.
-- كل تصنيف يحصل على درس واحد (lessons + lesson_sections +
-- lesson_citations)، بنفس أسلوب دروس tibb-ahkam-shariyya/madhahib-fiqh-muqaran
-- (تعريفي موجز: قسم body + قسم examples).
-- المصادر المعتمدة: تاريخ التشريع الإسلامي لمناع القطان (عصر النبوة
-- والصحابة والتابعين)، تاريخ التشريع الإسلامي لمحمد الخضري بك (نشأة
-- المدارس والتدوين)، تاريخ المذاهب الفقهية لمحمد أبو زهرة (تاريخ المذاهب
-- الأربعة والقضاء)، المدخل الفقهي العام لمصطفى الزرقا (المجامع
-- الفقهية والتقنين المعاصر ومجلة الأحكام العدلية).
-- حديث واحد استُشهد به، تحقَّق حرفياً عبر WebSearch قبل الإدراج (متفق
-- عليه): "خير الناس قرني ثم الذين يلونهم ثم الذين يلونهم" (رواه البخاري
-- 2652 ومسلم 2533 عن عبد الله بن مسعود).
-- ثلاث آيات تحقَّقت حرفياً محلياً من artifacts/majalis/public/data/quran
-- عبر حقل numberInSurah: الحشر 7 (حجية أوامر الرسول)، المائدة 49 (أصل
-- القضاء الشرعي)، الشورى 38 (أصل العمل الجماعي المجمعي).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الأربعة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) التشريع في عصر النبوة والصحابة والتابعين
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='15d97489-3037-4df7-9002-8dbc14d6966e' AND title='مراحل التشريع الإسلامي في عصر النبوة والصحابة والتابعين') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('مراحل التشريع الإسلامي في عصر النبوة والصحابة والتابعين', 'تعريف موجز بمراحل نشأة التشريع الإسلامي الثلاث الأولى: عصر النبوة والصحابة والتابعين', '15d97489-3037-4df7-9002-8dbc14d6966e', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'من الوحي المباشر إلى بدايات الاجتهاد', 'مرّ التشريع الإسلامي في نشأته الأولى بثلاث مراحل متتابعة. المرحلة الأولى: عصر النبوة، وفيها كان مصدر التشريع الوحي المباشر عبر القرآن الكريم والسنة النبوية، وتميّز بالتدرج في تنزيل الأحكام مراعاة لأحوال المكلَّفين، وبإمكان النسخ فيما يقتضيه تبدّل المصلحة، وكان النبي صلى الله عليه وسلم هو المرجع الوحيد عند الاختلاف يفصل فيه بالوحي أو بالاجتهاد المؤيَّد بالوحي. المرحلة الثانية: عصر الصحابة، وبعد وفاة النبي صلى الله عليه وسلم واتساع رقعة الدولة الإسلامية خارج الجزيرة العربية، واجه الصحابة مسائل مستجدة لم يرد فيها نص صريح، فاجتهدوا فيها اعتمادًا على فهمهم لمقاصد الشريعة، عبر الشورى الجماعية بين كبار الصحابة كعمر بن الخطاب وعلي بن أبي طالب وعبد الله بن مسعود وزيد بن ثابت، وظهرت في عهدهم بذور الإجماع والقياس كأدلة اجتهادية مكمّلة للنص. المرحلة الثالثة: عصر التابعين، وفيه بدأ التباعد الزمني عن عصر النص المباشر، فنشأت الحاجة إلى حفظ الفتاوى ونقلها، وتشكّلت بذور المدارس الفقهية الأولى حول مراكز العلم، أبرزها فقهاء المدينة السبعة الذين ورثوا فقه الصحابة المقيمين بالحجاز، وإبراهيم النخعي بالكوفة الذي ورث فقه عبد الله بن مسعود بالعراق.', 1),
    (v_lesson, 'examples', 'أصل حجية التشريع النبوي من القرآن', 'قال تعالى: ﴿مَّا أَفَاءَ اللَّهُ عَلَىٰ رَسُولِهِ مِنْ أَهْلِ الْقُرَىٰ فَلِلَّهِ وَلِلرَّسُولِ وَلِذِي الْقُرْبَىٰ وَالْيَتَامَىٰ وَالْمَسَاكِينِ وَابْنِ السَّبِيلِ كَيْ لَا يَكُونَ دُولَةً بَيْنَ الْأَغْنِيَاءِ مِنكُمْ ۚ وَمَا آتَاكُمُ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانتَهُوا ۚ وَاتَّقُوا اللَّهَ ۖ إِنَّ اللَّهَ شَدِيدُ الْعِقَابِ﴾ (الحشر: 7)، وقوله تعالى ﴿وَمَا آتَاكُمُ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانتَهُوا﴾ هو الأصل القرآني الذي اعتمده علماء أصول الفقه دليلاً على حجية كل ما شرّعه النبي صلى الله عليه وسلم من أوامر ونواهٍ، سواء ورد في القرآن أو استقلت به السنة، وهو ما بُني عليه اعتبار السنة النبوية مصدرًا مستقلاً للتشريع في عصر النبوة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'تاريخ التشريع الإسلامي — مناع القطان', 1);
  END IF;

  -- 2) المدارس الفقهية وتدوين الفقه
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='9e21069f-e027-4f26-b08a-a1e5065ce4e1' AND title='نشأة المدارس الفقهية وبدايات تدوين الفقه') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('نشأة المدارس الفقهية وبدايات تدوين الفقه', 'تعريف موجز بنشأة مدرستي أهل الحديث وأهل الرأي وبدايات تدوين الفقه الإسلامي', '9e21069f-e027-4f26-b08a-a1e5065ce4e1', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'مدرسة الحجاز ومدرسة العراق وبدايات التدوين', 'تشكّلت في عصر التابعين مدرستان فقهيتان كبيرتان تباينت مناهجهما تبعًا لظروف كل بيئة. مدرسة الحجاز (أهل الحديث)، ومركزها المدينة المنورة مقر الوحي ومهبط أكثر الأحاديث، فاعتمد فقهاؤها على النصوص المروية والآثار وعمل أهل المدينة، وقلّ اعتمادهم على الرأي لوفرة الأثر عندهم، وأبرز رجالها فقهاء المدينة السبعة كسعيد بن المسيب والقاسم بن محمد. مدرسة العراق (أهل الرأي)، ومركزها الكوفة التي بَعُدت عن مصادر النصوص المباشرة وكثرت فيها النوازل المستجدة نتيجة اتساع الفتوحات واختلاط الأعراف، فلجأ فقهاؤها إلى توسيع دائرة القياس والرأي المنضبط عند قلة الأثر الثابت عندهم، وأبرز رجالها إبراهيم النخعي ثم حماد بن أبي سليمان الذي تتلمذ عليه الإمام أبو حنيفة. أما التدوين الرسمي للفقه فبدأ في مطلع القرن الثاني الهجري، حين أمر الخليفة عمر بن عبد العزيز الأمصار بتدوين الحديث النبوي خشية ضياعه بموت حملته، فكان ذلك إيذانًا ببدء عصر التدوين الذي ازدهر بعده في العصر العباسي الأول بتدوين الفقه نفسه، ومن أبرز مصنفاته موطأ الإمام مالك في المدينة، وكتب أبي يوسف ومحمد بن الحسن الشيباني في العراق.', 1),
    (v_lesson, 'examples', 'فضل القرون الأولى التي نشأت فيها المدارس الفقهية', 'قال النبي صلى الله عليه وسلم: «خير الناس قرني، ثم الذين يلونهم، ثم الذين يلونهم» (متفق عليه، رواه البخاري 2652 ومسلم 2533 عن عبد الله بن مسعود رضي الله عنه)، وهذا الحديث هو الأصل النبوي في تفضيل القرون الثلاثة الأولى (الصحابة فالتابعون فتابعو التابعين) على من بعدهم، وفي هذه القرون بالذات نشأت المدارس الفقهية الأولى وبدأ تدوين الفقه، مما يفسّر المكانة العلمية الخاصة التي حظي بها فقه هذه الأجيال عند من جاء بعدهم.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'تاريخ التشريع الإسلامي — محمد الخضري بك', 1);
  END IF;

  -- 3) تاريخ المذاهب الأربعة والاجتهاد والقضاء
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='fa17da48-6a3c-44db-9896-06a9ea573776' AND title='تاريخ نشأة المذاهب الفقهية الأربعة وعلاقتها بنظام القضاء') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تاريخ نشأة المذاهب الفقهية الأربعة وعلاقتها بنظام القضاء', 'تعريف موجز بالتتابع التاريخي لنشأة المذاهب الأربعة وتطور علاقتها بمناصب القضاء والإفتاء', 'fa17da48-6a3c-44db-9896-06a9ea573776', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'التتابع الزمني للمذاهب وتقيّد القضاء بها', 'نشأت المذاهب الفقهية الأربعة المتبوعة في تتابع زمني عبر نحو قرن من الزمان: فأولها ظهورًا مذهب الإمام أبي حنيفة (ت 150هـ) في الكوفة، ثم مذهب الإمام مالك بن أنس (ت 179هـ) في المدينة، ثم مذهب الإمام الشافعي (ت 204هـ) الذي جمع بين منهجي الحجاز والعراق ودوّن أصول الاستدلال، ثم مذهب الإمام أحمد بن حنبل (ت 241هـ) آخرها نشأة. وقد ارتبط تاريخ هذه المذاهب بتطور نظام القضاء الإسلامي ارتباطًا وثيقًا: ففي القرون الأولى كان القاضي يجتهد برأيه مستقلاً غير مقيَّد بمذهب معيّن، ثم مع استقرار المذاهب وتدوين فروعها بدأت الدول الإسلامية المتعاقبة تعتمد مذهبًا بعينه أساسًا للقضاء الرسمي في أقاليمها ضبطًا لصدور الأحكام ومنعًا لاضطراب القضاء بتعدد الاجتهادات، فاعتمدت الدولة العثمانية المذهب الحنفي أساسًا لقضائها ونظّمت عليه محاكمها. كما استقل في هذه الحقبة منصب "المفتي" عن منصب "القاضي": فالقاضي يُلزم الناس بحكمه القضائي الفاصل في الخصومات، والمفتي يُخبر بالحكم الشرعي دون إلزام قضائي، وقد تطوّر منصب الإفتاء حتى صار له مؤسساته الرسمية المستقلة في الدول الإسلامية المعاصرة.', 1),
    (v_lesson, 'examples', 'أصل القضاء بما أنزل الله من القرآن', 'قال تعالى: ﴿وَأَنِ احْكُم بَيْنَهُم بِمَا أَنزَلَ اللَّهُ وَلَا تَتَّبِعْ أَهْوَاءَهُمْ وَاحْذَرْهُمْ أَن يَفْتِنُوكَ عَن بَعْضِ مَا أَنزَلَ اللَّهُ إِلَيْكَ﴾ (المائدة: 49)، وهي الأصل القرآني في وجوب استناد القاضي في حكمه إلى ما أنزل الله من الشريعة لا إلى الهوى، وعلى هذا الأصل قامت مؤسسة القضاء الإسلامي منذ عصر النبوة، ثم تطورت آلياتها عبر العصور حتى صار القضاء في أغلب الدول الإسلامية مقيّدًا بمذهب فقهي معتبر تحقيقًا لانضباط الأحكام واستقرارها.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'تاريخ المذاهب الفقهية — محمد أبو زهرة', 1);
  END IF;

  -- 4) المجامع الفقهية والتقنين المعاصر
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='741c0134-fc63-4d94-8af2-f07729faf4b7' AND title='المجامع الفقهية المعاصرة ودورها في التقنين الفقهي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('المجامع الفقهية المعاصرة ودورها في التقنين الفقهي', 'تعريف موجز بنشأة المجامع الفقهية المعاصرة وحركة تقنين الفقه الإسلامي في القرنين الأخيرين', '741c0134-fc63-4d94-8af2-f07729faf4b7', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'من الاجتهاد الفردي إلى الاجتهاد الجماعي والتقنين', 'شهد العصر الحديث تحوّلاً منهجيًا مهمًا في التعامل مع النوازل المستجدة، تمثّل في نشأة المجامع الفقهية الجماعية كبديل مؤسسي مكمّل للاجتهاد الفردي، نظرًا لتعقّد كثير من المسائل المعاصرة (كالنوازل الطبية والاقتصادية) وحاجتها إلى تضافر خبرات متعددة التخصصات. ومن أبرز هذه المجامع: مجمع الفقه الإسلامي التابع لرابطة العالم الإسلامي بمكة المكرمة، تأسس سنة 1398هـ، ومجمع الفقه الإسلامي الدولي التابع لمنظمة التعاون الإسلامي بجدة، تأسس سنة 1401هـ وهو الأوسع تمثيلاً لعلماء المذاهب والبلدان الإسلامية. تصدر هذه المجامع قراراتها عبر آلية الشورى الجماعية بعد عرض المسألة على المتخصصين الشرعيين والفنيين ومناقشتها. وإلى جانب حركة المجامع، نشأت حركة موازية هي "التقنين الفقهي المعاصر"، أي تحويل الأحكام الفقهية من صيغتها التقليدية في كتب الفقه إلى مواد قانونية مرقمة صالحة للتطبيق القضائي المباشر، وكان أول تقنين فقهي رسمي في التاريخ الإسلامي الحديث هو "مجلة الأحكام العدلية" التي أصدرتها الدولة العثمانية سنة 1293هـ (1876م) مستمدة موادها من فقه المذهب الحنفي، وقد مهّدت هذه التجربة الطريق أمام قوانين الأحوال الشخصية والمعاملات المستمدة من الفقه الإسلامي في كثير من الدول الإسلامية المعاصرة.', 1),
    (v_lesson, 'examples', 'أصل الشورى الجماعية من القرآن', 'قال تعالى: ﴿وَالَّذِينَ اسْتَجَابُوا لِرَبِّهِمْ وَأَقَامُوا الصَّلَاةَ وَأَمْرُهُمْ شُورَىٰ بَيْنَهُمْ وَمِمَّا رَزَقْنَاهُمْ يُنفِقُونَ﴾ (الشورى: 38)، وهي الأصل القرآني في اعتماد الشورى منهجًا في الأمور العامة، وعليها يُبنى المنهج المؤسسي للمجامع الفقهية المعاصرة التي تصدر قراراتها عبر تداول جماعي بين علماء متعددين بدل اقتصار النظر في النوازل المعقدة على اجتهاد فرد واحد.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المدخل الفقهي العام — مصطفى الزرقا', 1);
  END IF;

  -- تحديث حالة التصنيفات الأربعة إلى منشور بعد اكتمال محتواها
  UPDATE categories SET status='published'
  WHERE id IN (
    '15d97489-3037-4df7-9002-8dbc14d6966e', '9e21069f-e027-4f26-b08a-a1e5065ce4e1',
    'fa17da48-6a3c-44db-9896-06a9ea573776', '741c0134-fc63-4d94-8af2-f07729faf4b7'
  );
END $$;
